     1→/**
     2→ * API Route: End Conversation
     3→ *
     4→ * POST /api/conversations/[id]/end
     5→ *
     6→ * Closes a conversation, generates summary, evaluation, and parent note.
     7→ * Part of Session Summary & Unified Archive feature.
     8→ */
     9→
    10→import { NextRequest, NextResponse } from 'next/server';
    11→import { prisma } from '@/lib/db';
    12→import { logger } from '@/lib/logger';
    13→import { endConversationWithSummary } from '@/lib/conversation/summary-generator';
    14→import { inactivityMonitor } from '@/lib/conversation/inactivity-monitor';
    15→
    16→interface RouteParams {
    17→  params: Promise<{
    18→    id: string;
    19→  }>;
    20→}
    21→
    22→/**
    23→ * POST /api/conversations/[id]/end
    24→ *
    25→ * End a conversation and generate summary.
    26→ *
    27→ * Body:
    28→ * - userId: Required for authorization
    29→ * - reason: Optional reason for ending ('explicit' | 'timeout' | 'system')
    30→ */
    31→export async function POST(request: NextRequest, context: RouteParams) {
    32→  try {
    33→    const { id: conversationId } = await context.params;
    34→    const body = await request.json();
    35→    const { userId, reason = 'explicit' } = body;
    36→
    37→    if (!userId) {
    38→      return NextResponse.json(
    39→        { error: 'userId is required' },
    40→        { status: 400 }
    41→      );
    42→    }
    43→
    44→    // Verify conversation exists and belongs to user
    45→    const conversation = await prisma.conversation.findFirst({
    46→      where: {
    47→        id: conversationId,
    48→        userId,
    49→      },
    50→    });
    51→
    52→    if (!conversation) {
    53→      return NextResponse.json(
    54→        { error: 'Conversation not found' },
    55→        { status: 404 }
    56→      );
    57→    }
    58→
    59→    if (!conversation.isActive) {
    60→      return NextResponse.json(
    61→        { error: 'Conversation already closed' },
    62→        { status: 400 }
    63→      );
    64→    }
    65→
    66→    // Stop inactivity tracking
    67→    inactivityMonitor.stopTracking(conversationId);
    68→
    69→    // Generate summary
    70→    const result = await endConversationWithSummary(conversationId);
    71→
    72→    if (!result) {
    73→      return NextResponse.json(
    74→        { error: 'Failed to generate summary' },
    75→        { status: 500 }
    76→      );
    77→    }
    78→
    79→    logger.info('Conversation ended', {
    80→      conversationId,
    81→      userId,
    82→      reason,
    83→      summaryLength: result.summary.length,
    84→      topicsCount: result.topics.length,
    85→    });
    86→
    87→    return NextResponse.json({
    88→      success: true,
    89→      conversationId,
    90→      reason,
    91→      summary: result.summary,
    92→      topics: result.topics,
    93→      learningsCount: result.learningsCount,
    94→    });
    95→  } catch (error) {
    96→    logger.error('Failed to end conversation', { error: String(error) });
    97→    return NextResponse.json(
    98→      { error: 'Failed to end conversation' },
    99→      { status: 500 }
   100→    );
   101→  }
   102→}
   103→
   104→/**
   105→ * GET /api/conversations/[id]/end
   106→ *
   107→ * Get the summary for a closed conversation.
   108→ */
   109→export async function GET(request: NextRequest, context: RouteParams) {
   110→  try {
   111→    const { id: conversationId } = await context.params;
   112→    const { searchParams } = new URL(request.url);
   113→    const userId = searchParams.get('userId');
   114→
   115→    if (!userId) {
   116→      return NextResponse.json(
   117→        { error: 'userId is required' },
   118→        { status: 400 }
   119→      );
   120→    }
   121→
   122→    const conversation = await prisma.conversation.findFirst({
   123→      where: {
   124→        id: conversationId,
   125→        userId,
   126→      },
   127→      select: {
   128→        id: true,
   129→        maestroId: true,
   130→        isActive: true,
   131→        summary: true,
   132→        keyFacts: true,
   133→        topics: true,
   134→        updatedAt: true,
   135→      },
   136→    });
   137→
   138→    if (!conversation) {
   139→      return NextResponse.json(
   140→        { error: 'Conversation not found' },
   141→        { status: 404 }
   142→      );
   143→    }
   144→
   145→    return NextResponse.json({
   146→      conversationId: conversation.id,
   147→      maestroId: conversation.maestroId,
   148→      isActive: conversation.isActive,
   149→      summary: conversation.summary,
   150→      keyFacts: conversation.keyFacts ? JSON.parse(conversation.keyFacts) : null,
   151→      topics: JSON.parse(conversation.topics),
   152→      closedAt: conversation.isActive ? null : conversation.updatedAt,
   153→    });
   154→  } catch (error) {
   155→    logger.error('Failed to get conversation summary', { error: String(error) });
   156→    return NextResponse.json(
