   466→        // Stop inactivity monitoring
   467→        inactivityMonitor.stopTracking(conversationId);
   468→
   469→        // Calculate session duration
   470→        const duration = state.sessionStartedAt
   471→          ? Math.round((Date.now() - state.sessionStartedAt.getTime()) / 60000)
   472→          : 0;
   473→
   474→        try {
   475→          // Generate summary
   476→          const result = await generateSummary(conversationId);
   477→
   478→          if (result) {
