   580→      },
   581→
   582→      switchToCharacter: (character, type, profile, _reason) => {
   583→        const state = get();
   584→
   585→        // 1. Save current conversation to its bucket
   586→        const savedConversations = saveCurrentConversation(state);
   587→
   588→        // 2. Create new active character
   589→        const activeCharacter = createActiveCharacter(character, type, profile);
   590→
   591→        // 3. Load existing messages for new character (or start fresh)
   592→        let messages = loadConversationMessages(savedConversations, character.id);
   593→
   594→        if (messages.length === 0) {
   595→          // No existing conversation - add greeting
   596→          messages = [
   597→            {
   598→              id: crypto.randomUUID(),
   599→              role: 'assistant',
   600→              content: activeCharacter.greeting,
   601→              timestamp: new Date(),
   602→              characterId: activeCharacter.id,
   603→              characterType: type,
   604→            },
   605→          ];
   606→        }
   607→
   608→        // 4. Update history
   609→        const newHistory = [
   610→          ...state.characterHistory,
   611→          { type, id: character.id, timestamp: new Date() },
   612→        ];
   613→
   614→        set({
   615→          activeCharacter,
   616→          messages,
   617→          characterHistory: newHistory,
   618→          pendingHandoff: null,
   619→          conversationsByCharacter: savedConversations,
   620→        });
   621→      },
   622→
   623→      switchToCoach: (profile) => {
   624→        const coach = getDefaultSupportTeacher();
   625→        get().switchToCharacter(coach, 'coach', profile);
   626→      },
   627→
   628→      switchToMaestro: (maestro, profile) => {
   629→        get().switchToCharacter(maestro, 'maestro', profile);
   630→      },
